script:
frappe.ui.form.on("Check In", {
    refresh(frm) {
        toggle_new_item(frm);
    },

    override_item(frm) {
        toggle_new_item(frm);
    }
});

function toggle_new_item(frm) {
    if (frm.doc.override_item) {
        frm.set_df_property("new_item", "hidden", 0);
    } else {
        frm.set_df_property("new_item", "hidden", 1);
        frm.set_value("new_item", null);
    }
}
